// ************************************** Image Mark Managing Module Start *********************************************** //
var navigatorName = "Microsoft Internet Explorer";  
var div_orgX = 465;
var div_orgY;
     if(document.uniqueID){ 
        div_orgY =620;
     }
	 else{
	    div_orgY =626;
	 }
        // div left-top position
var div_orgWidth = 800;                 // div original position
var div_marginTop = 0;                 // div magin-top size 
var markWidth = 27, markHeight = 42;    // mark (width * height)

var img_orgX, img_orgY;                 // image left-top position
var img_disWidth, img_disHeight;        // Display image size
var img_disRatio;                       // Display image ratio

var rowAddFlag = false;                 // true: add, false: normal
var rowAddIdx;                          // uid when user is append the "markObj" tag into "FurniDetailDiv" tag.
var rowDelFlag = false;                 // true: removing, false: normal
var rowDelIdx;                          // uid when user is click the removing button.


function onMarkObjCreate(idx, tooltip, xPos, yPos, state) {

    onMarkObjDestroy(idx);

    // Create mark object.
    var markObj = document.createElement("img");
    if (markObj != undefined) {
        markObj.setAttribute("id", "draggable" + idx);
        markObj.setAttribute("name", "draggable");

        if (state)
            markObj.setAttribute("src", "../../Content/img/mark_sel.png");
        else
            markObj.setAttribute("src", "../../Content/img/mark.png");

        xPos = img_orgX + xPos / img_disRatio;
        yPos = img_orgY + yPos / img_disRatio;

        markObj.setAttribute("style", "position:absolute;top:" + yPos + "px;left:" + xPos + 
                                                        "px;width:" + markWidth + "px;height:" + markHeight + "px;");
        markObj.setAttribute("title", tooltip);
    }
    else
        alert("markObj is undefined");

    // Add "markObj <img>"tag into "FurniDetailDiv <div>" tag
    var FurniDetailDiv = document.getElementById("FurniDetailDiv");
    if (FurniDetailDiv != undefined)
        FurniDetailDiv.appendChild(markObj);
    else
        alert("FurniDetailDiv is undefined");
}

function onMarkObjDestroy(idx) {

    var markObj = document.getElementById("draggable" + idx);
    if (markObj != undefined) {
        var FurniDetailDiv = document.getElementById("FurniDetailDiv");
        if (FurniDetailDiv != undefined)
            FurniDetailDiv.removeChild(markObj);
    }
}

function onLoad(e) {

    img_disWidth = $("#disWidth").val();
    img_disHeight = $("#disHeight").val();
    img_disRatio = $("#disRatio").val();
    
    img_orgX = div_orgX + (div_orgWidth - img_disWidth) / 2 - markWidth / 2;
    img_orgY = div_orgY + div_marginTop - markHeight;
}

function onDataBound(e) {

    if (rowDelFlag) {
        rowDelFlag = false;
        onMarkObjDestroy(rowDelIdx);
    }

    onMarkObjDestroy(0);
}

function onRowDataBound(e) {

    var result = [];    
    $.each(e.dataItem, function (key, value) { result.push(value); });

    var idx = result[0];
    var tooltip = result[2];
    var xPos = result[6];
    var yPos = result[7];

    onMarkObjCreate(idx, tooltip, xPos, yPos, false);
}

function onSave(e) {
    var result = [];
    $.each(e.values, function (key, value) { result.push(value); });

    if (rowAddFlag) {
        if (result[0] == "") {
            alert("请输入名称。");
            $("#name").focus();
            return false;
        }
        else if (result[1] == "") {
        alert("请输入规格。");
        $("#standard").focus();
        return false;
        }
        else if (result[2] == "") {
            alert("请输入功能。");
            $("#func").focus();
            return false;
        }
        else if (result[3] == "") {
            alert("请输入颜色。");
            $("#color").focus();
            return false;
        }
    }
}

function onEdit(e) {

    rowDelFlag = false;

    onMarkObjDestroy(0);

    var result = [];
    $.each(e.dataItem, function (key, value) { result.push(value); });

    var idx = result[0];
    var tooltip = result[2];
    var xPos = result[6];
    var yPos = result[7];

    if (idx == 0) {
        xPos = img_disWidth / 2;
        yPos = img_disHeight / 2;

        rowAddFlag = true;
        rowAddIdx = idx;

        $("#xpos").val(xPos);
        $("#ypos").val(yPos);
    }
    else
        onMarkObjDestroy(idx);

    onMarkObjCreate(idx, tooltip, xPos, yPos, true);

    $("#draggable" + idx).draggable({
        start: function (event, ui) {
        },
        drag: function (event, ui) {
            xPos = (ui.position.left - img_orgX) * img_disRatio;
            yPos = (ui.position.top - img_orgY) * img_disRatio;
            $("#xpos").val(xPos);
            $("#ypos").val(yPos);
        },
        stop: function (event, ui) {
        }
    });
}

function onDelete(e) {

    var result = [];
    $.each(e.dataItem, function (key, value) { result.push(value); });
    var idx = result[0];

    rowDelFlag = true;
    rowDelIdx = idx;

    onMarkObjDestroy(0);
}

// ************************************** Image Mark Managing Module End *************************************************** //


