function getTypeHtmlCode(classid, giftid) {
    var $loading = $('<img src="' + rootUri + 'Content/Images/ajaxLoading.gif" alt="loading">');
    $('#typelist-view').html($loading);
    $.ajax({
        url: rootUri + "Gift/_RetrieveGiftTypeList?classify_uid=" + classid + "&gift_uid=" + giftid + "&rand=" + Math.random(),
        type: 'GET',
        success: onClassifySuccess,
        error: function (xhr, status) {
            alert("error - " + xhr);
        }
    });
}

function onClassifySuccess(data, textStatus, xhr) {
    $("#typelist-view").html(data);

    //If user fail to submit, then reset current set typelist.
    if (typeof curr_typelist != 'undefined') {
        for (var i=0; i < curr_typelist.length; i++) {
            $("input[name=" + curr_typelist[i]["name"] + "]").attr("checked", "checked");
        }
    }
}

function TabSelect(tab_index) {
    var tabstrip = $("#gifttable").data("tTabStrip");
    var item = $("li", tabstrip.element)[tab_index];
    tabstrip.select(item);
}

function checkGiftInputData() {
    var isFormValid = true;

    $(".required").removeClass("input-validation-error");
    $(".validation-tip").hide();

    if ($("#classify").val() == 2) {
        TabSelect(0);
        $("#classify").addClass("input-validation-error");
        $("#classify").focus();

        $("#error_classify").text("请选择礼品分类").show();
        return false;
    }
    else {
        $("#classify").removeClass("input-validation-error");
    }

    $(".required").each(function () {
        if ($.trim($(this).val()).length == 0) {
            TabSelect(0);
            $(this).addClass("input-validation-error");
            $(this).focus();

            $('#error_' + $(this).attr("id")).text("不能为空").show();

            isFormValid = false;
            return isFormValid;
        }
        else {
            $(this).removeClass("input-validation-error");
        }
    });

    var itemName = $("#name").val();
    if (!validateSpecialChar(itemName)) {
        TabSelect(0);
        $("#name").addClass("input-validation-error");
        $("#name").focus();

        $('#error_' + $("#name").attr("id")).text("名字有特殊字符").show();

        return false;
    }
    else {
        $(this).removeClass("input-validation-error");
    }

    var orderNum = $("#display_order").val();
    if (orderNum.length == 0 || !validateNumeric(orderNum)) {
        $("#display_order").addClass("input-validation-error");
        $("#error_display_order").text("请输入数字").show();
        TabSelect(0);
        return false;
    } else {
        $("#display_order").removeClass("input-validation-error");
    }

    var acttype = $("#acttype").val();
    if (acttype != "edit") {
        var imgPath = $("#listimg").val();
        if (imgPath.length == 0) {
            $("#listimg").addClass("input-validation-error");
            TabSelect(1);
            return false;
        }
        else {
            $("#listimg").removeClass("input-validation-error");
        }
    }  


    return isFormValid;
}




